<script setup lang="ts">import{ref,computed}from"vue";import{api,session}from"../api";const emit=defineEmits<{close:[];success:[]}>();const phone=ref(""),code=ref(""),message=ref("");const validPhone=computed(()=>/^1[3-9]\d{9}$/.test(phone.value));async function sms(){if(!validPhone.value)return;try{const r=await api.sendSms(phone.value);if(r.debugCode)code.value=r.debugCode;message.value="验证码已发送"}catch(e){message.value=e instanceof Error?e.message:"发送失败"}}async function login(){if(!validPhone.value){message.value="请输入正确的11位手机号";return}if(!/^\d{6}$/.test(code.value)){message.value="请输入6位数字验证码";return}try{const r=await api.login(phone.value,code.value);session.set(r.accessToken);localStorage.setItem("patient_phone",phone.value);emit("success")}catch(e){message.value=e instanceof Error?e.message:"登录失败"}}</script><template><div class="overlay" @click.self="emit('close')"><section class="sheet login-sheet"><i class="handle"/><h2>手机号登录</h2><p>登录后可预约挂号、管理就诊人</p><label>手机号<input inputmode="numeric" maxlength="11" :value="phone" @input="phone=($event.target as HTMLInputElement).value.replace(/\D/g,'')" placeholder="请输入11位手机号"/></label><div class="sms-row"><input inputmode="numeric" maxlength="6" :value="code" @input="code=($event.target as HTMLInputElement).value.replace(/\D/g,'')" placeholder="6位验证码"/><button :disabled="!validPhone" @click="sms">获取验证码</button></div><p v-if="message" class="form-message">{{message}}</p><button class="primary wide" :disabled="!validPhone||code.length!==6" @click="login">登录 / 自动注册</button></section></div></template>
